#include <bits/stdc++.h>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    while (n--) {
        long long x, y;
        cin >> x >> y;
        long long pos = 0;
        while (true) {
            long long s = x + y;
            if (s % 2 != 0) break;
            long long d = x - y;
            if (s % 4 == 0) { // vertical
                long long s_div2 = s / 2;
                pos = pos * 2 + (s_div2 % 2);
                x = d / 2;
                y = (s_div2 - 1) / 2;
            } else { // horizontal
                long long s_div2 = (s - 1) / 2;
                pos = pos * 2 + (s_div2 % 2);
                x = (d + 1) / 2;
                y = s_div2 / 2;
            }
        }
        long long a = x - (x + y + 1) / 2;
        long long b = y - (x + y - 1) / 2;
        pos = pos * 2 + ((a + b) % 2 != 0);
        int curve = 1;
        if (a % 2) {
            curve += 1;
            if (b % 2) curve += 1;
        } else if (b % 2) {
            curve += 3;
        }
        cout << curve << ' ' << pos + 1 << '\n';
    }
    return 0;
}
